#include <stdio.h>
#include <stdlib.h>
int main() {
    int N;
    scanf("%d", &N);
    int* heights = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &heights[i]);
    }
    int maxCount = 0;
    for (int i = 0; i < N - 1; i++) {
        int min = heights[i] < heights[i + 1] ? heights[i] : heights[i + 1];
        int max = heights[i] > heights[i + 1] ? heights[i] : heights[i + 1];
        for (int j = min; j <= max; j++) {
            int count = 0;
            for (int k = 0; k < N - 1; k++) {
                int min2 = heights[k] < heights[k + 1] ? heights[k] : heights[k + 1];
                int max2 = heights[k] > heights[k + 1] ? heights[k] : heights[k + 1];
                if (j >= min2 && j <= max2) {
                    count++;
                }
            }
            if (count > maxCount) {
                maxCount = count;
            }
        }
    }
    printf("%d\n", maxCount);
    return 0;
}

